import numpy as np
from scipy.spatial import ConvexHull

def convex_hull_4d(points):
    # Confirm that each point has four coordinates
    if not all(len(point) == 4 for point in points):
        raise ValueError("Each point must have four coordinates.")

    # Convert points to a numpy array
    points = np.array(points)

    # Special cases
    if len(points) == 1:
        return [points[0]]
    if len(points) == 2:
        return [points[0], points[1]]
    if len(points) == 3:
        if np.cross(points[1] - points[0], points[2] - points[0]).all() == 0:
            return [points[0], points[1], points[2]]

    # Calculate the convex hull
    hull = ConvexHull(points)

    # Return the vertices of the convex hull
    return [points[vertex] for vertex in hull.vertices]
